import { Component, DestroyRef, computed, effect, inject, input, output, signal, untracked } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormArray, FormControl, FormGroup, NonNullableFormBuilder, ReactiveFormsModule } from '@angular/forms';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { SelectModule } from 'primeng/select';
import { MultiSelectModule } from 'primeng/multiselect';
import { ButtonModule } from 'primeng/button';
import { TranslatePipe } from '@ngx-translate/core';
import {
  TARGETS_BY_SCOPE,
  TARGET_ACTIONS,
  TARGET_LABELS,
} from '../../models/app-store-permissions.constants';

type PermissionRowGroup = FormGroup<{
  scope: FormControl<string>;
  target: FormControl<string>;
  actions: FormControl<string[]>;
}>;

interface CommittedRow {
  scope: string;
  target: string;
  label: string;
  actions: string[];
}

@Component({
  selector: 'app-permissions-picker',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, SelectModule, MultiSelectModule, ButtonModule, TranslatePipe],
  templateUrl: './app-permissions-picker.component.html',
})
export class AppPermissionsPickerComponent {
  private readonly fb = inject(NonNullableFormBuilder);
  private readonly destroyRef = inject(DestroyRef);

  readonly value       = input<string[]>([]);
  readonly readonly    = input<boolean>(false);
  readonly valueChange = output<string[]>();

  // ── Dropdown option lists ─────────────────────────────────────────────────
  readonly scopeOptions = Object.keys(TARGETS_BY_SCOPE).map(s => ({ label: s, value: s }));

  getTargetOptions(scope: string) {
    return (TARGETS_BY_SCOPE[scope] ?? []).map(t => ({
      label: TARGET_LABELS[t] ?? t,
      value: t,
    }));
  }

  getActionOptions(target: string) {
    return (TARGET_ACTIONS[target] ?? ['list', 'get', 'create', 'update', 'delete']).map(a => ({
      label: a,
      value: a,
    }));
  }

  // ── Committed rows FormArray ──────────────────────────────────────────────
  readonly form = new FormArray<PermissionRowGroup>([]);

  // ── Draft FormGroup (outside the array — not emitted until confirmed) ─────
  readonly draft: PermissionRowGroup = this.fb.group({
    scope:   this.fb.control('client'),
    target:  this.fb.control(''),
    actions: this.fb.control<string[]>([]),
  });

  readonly draftInvalid = signal(false);

  constructor() {
    effect(() => {
      const value = this.value();
      untracked(() => this.buildForm(value));
    });

    this.form.valueChanges
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(() => this.emit());
  }

  // ── Committed rows display ────────────────────────────────────────────────
  get committedRows(): CommittedRow[] {
    return this.form.controls.map(c => {
      const { scope, target, actions } = c.getRawValue();
      return { scope, target, label: TARGET_LABELS[target] ?? target, actions };
    });
  }

  get draftScope(): string {
    return this.draft.getRawValue().scope;
  }

  get draftTarget(): string {
    return this.draft.getRawValue().target;
  }

  // ── Draft cascade handlers ────────────────────────────────────────────────
  onDraftScopeChange(): void {
    this.draft.patchValue({ target: '', actions: [] });
    this.draftInvalid.set(false);
  }

  onDraftTargetChange(): void {
    this.draft.patchValue({ actions: [] });
    this.draftInvalid.set(false);
  }

  // ── Confirm draft → push to committed array ───────────────────────────────
  confirmDraft(): void {
    const { target, actions } = this.draft.getRawValue();
    if (!target || actions.length === 0) {
      this.draftInvalid.set(true);
      return;
    }
    this.draftInvalid.set(false);
    this.form.push(this.createRow(this.draft.getRawValue()));
    this.draft.reset({ scope: 'client', target: '', actions: [] });
  }

  removeRow(index: number): void {
    this.form.removeAt(index);
  }

  // ── Private helpers ───────────────────────────────────────────────────────
  private createRow(value: { scope: string; target: string; actions: string[] }): PermissionRowGroup {
    return this.fb.group({
      scope:   this.fb.control(value.scope),
      target:  this.fb.control(value.target),
      actions: this.fb.control(value.actions),
    });
  }

  /** Reverse-maps an entity target to the scope that owns it (scope is UI-only). */
  private scopeForTarget(target: string): string {
    for (const [scope, targets] of Object.entries(TARGETS_BY_SCOPE)) {
      if (targets.includes(target)) return scope;
    }
    return 'client';
  }

  private buildForm(v: string[]): void {
    this.form.clear({ emitEvent: false });
    // Input format: ["asset:list", "asset:get"] — "entity:action" strings.
    // Group actions by entity target; derive the (UI-only) scope from the target.
    const byTarget: Record<string, string[]> = {};
    for (const perm of v) {
      const colonIdx = perm.indexOf(':');
      if (colonIdx === -1) continue;
      const target = perm.slice(0, colonIdx);
      const action = perm.slice(colonIdx + 1);
      (byTarget[target] ??= []).push(action);
    }
    for (const [target, actions] of Object.entries(byTarget)) {
      this.form.push(
        this.createRow({ scope: this.scopeForTarget(target), target, actions }),
        { emitEvent: false },
      );
    }
  }

  private emit(): void {
    // Output format: ["asset:list", "asset:get"] — "entity:action" strings.
    const result: string[] = [];
    for (const row of this.form.controls) {
      const { target, actions } = row.getRawValue();
      if (!target || actions.length === 0) continue;
      for (const action of actions) {
        const perm = `${target}:${action}`;
        if (!result.includes(perm)) result.push(perm);
      }
    }
    this.valueChange.emit(result);
  }

  // ── Readonly helpers ──────────────────────────────────────────────────────
  // Input format: ["asset:list", "asset:get"] — parse for display.
  readonly selectedItems = computed(() => {
    const rows: { target: string; label: string; actions: string[] }[] = [];
    const byTarget: Record<string, string[]> = {};
    for (const perm of this.value()) {
      const colonIdx = perm.indexOf(':');
      if (colonIdx === -1) continue;
      const target = perm.slice(0, colonIdx);
      const action = perm.slice(colonIdx + 1);
      (byTarget[target] ??= []).push(action);
    }
    for (const [target, actions] of Object.entries(byTarget)) {
      rows.push({ target, label: TARGET_LABELS[target] ?? target, actions });
    }
    return rows;
  });
}
