import { Component, computed, inject, input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { TranslatePipe, TranslateService } from '@ngx-translate/core';
import { AppVisibilityBadgeComponent } from '../app-visibility-badge/app-visibility-badge.component';
import { ImgFallbackDirective } from '../../../../shared/directives/img-fallback.directive';
import { getFeeLabel } from '../../utils/fee.utils';
import { AppVisibility, FeeModel, IntegrationPoint, AVAILABLE_SCREENS } from '../../models/app-store.models';
import { TARGET_LABELS } from '../../models/app-store-permissions.constants';

export interface AppPreviewData {
  name: string;
  shortDescription: string;
  description: string;
  iconUrl?: string;
  developerName: string;
  visibility: AppVisibility;
  feeModel: FeeModel | null;
  integrationPoints?: IntegrationPoint[];
  hasHealthCheck?: boolean;
}

@Component({
  selector: 'app-listing-preview',
  imports: [CommonModule, TranslatePipe, AppVisibilityBadgeComponent, ImgFallbackDirective],
  templateUrl: './app-listing-preview.component.html',
  styleUrl: './app-listing-preview.component.scss',
})
export class AppListingPreviewComponent {
  private readonly translateService = inject(TranslateService);

  readonly data = input.required<AppPreviewData>();
  readonly isEditMode = input<boolean>(false);

  getFeeLabel(feeModel: FeeModel | null): string {
    return getFeeLabel(feeModel, this.translateService);
  }

  readonly allPermissions = computed(() => {
    const points = this.data().integrationPoints ?? [];
    const seen = new Set<string>();
    const result: string[] = [];
    for (const point of points) {
      for (const perm of point.requiredPermissions) {
        if (!seen.has(perm)) {
          seen.add(perm);
          result.push(perm);
        }
      }
    }
    return result;
  });

  getScreenName(screenId: string): string {
    return AVAILABLE_SCREENS.find((s) => s.id === screenId)?.name ?? screenId;
  }

  getPermissionLabel(permission: string): string {
    const [target, action] = permission.split(':');
    const targetLabel = TARGET_LABELS[target] ?? target;
    return `${targetLabel} (${action})`;
  }
}
