import {
  AVAILABLE_SCREENS,
  AppDefinition,
  AppVersion,
  AppVisibility,
  FeeModel,
  FeeType,
  IntegrationPoint,
} from '../../models/app-store.models';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import {
  AfterViewInit,
  Component,
  DestroyRef,
  Signal,
  TemplateRef,
  ViewChild,
  computed,
  inject,
  signal,
} from '@angular/core';
import { AppListingPreviewComponent, AppPreviewData } from '../../components/app-listing-preview/app-listing-preview.component';
import { CheckboxChangeEvent, CheckboxModule } from 'primeng/checkbox';
import { CommonModule, Location, formatCurrency } from '@angular/common';
import {
  FormArray,
  FormBuilder,
  FormGroup,
  FormsModule,
  ReactiveFormsModule,
  Validators,
} from '@angular/forms';
import {
  SubmitAppVersionRequest,
  VersionBumpType,
} from '../../models/api/app-store-api.models';
import { catchError, finalize, map, of, startWith, switchMap, tap } from 'rxjs';
import {
  createDropdownField,
  createTextAreaField,
} from '../../../../shared/models/form-field.model';
import { isDefined, isNullOrUndefined } from '../../../../shared/utils';
import { takeUntilDestroyed, toSignal } from '@angular/core/rxjs-interop';

import { AdaptiveLayoutComponent } from '../../../../shared/components/splitter/adaptive-layout/adaptive-layout.component';
import { AppPermissionsPickerComponent } from '../../components/app-permissions-picker/app-permissions-picker.component';
import { AppStoreService } from '../../services/app-store.service';
import { AppVersionService } from '../../services/app-version.service';
import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';
import { ClientDataService } from '../../../clients/services/client-data.service';
import { InputNumberModule } from 'primeng/inputnumber';
import { InputTextModule } from 'primeng/inputtext';
import { LayoutService } from '../../../../layouts/services/layout.service';
import { ModalFormService } from '../../../../shared/services/forms/modal-form.service';
import { ModalListFormComponent } from '../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { MultiSelectModule } from 'primeng/multiselect';
import { PanelConfig } from '../../../../shared/models/layout.model';
import { SelectModule } from 'primeng/select';
import { Step } from '../../../../shared/models/stepper.model';
import { StepperModule } from 'primeng/stepper';
import { TextareaModule } from 'primeng/textarea';
import { UserSessionService } from '../../../../core/services/user-session.service';
import { isEqual } from 'lodash-es';

export interface AppFormValue {
  basicInfo: {
    name: string;
    shortDescription: string;
    description: string;
    iconUrl?: string;
    healthCheckUrl?: string;
  };
  publishing: {
    visibility: AppVisibility;
    feeType: 'free' | FeeType;
    feeAmount: number | null;
  };
  integration: {
    points: IntegrationPoint[];
  };
}

@Component({
  selector: 'app-create-wizard',
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    ReactiveFormsModule,
    ButtonModule,
    InputTextModule,
    InputNumberModule,
    TextareaModule,
    SelectModule,
    MultiSelectModule,
    CheckboxModule,
    CardModule,
    AppPermissionsPickerComponent,
    AdaptiveLayoutComponent,
    AppListingPreviewComponent,
    StepperModule,
  ],
  templateUrl: './app-create-wizard.component.html',
  styleUrls: ['./app-create-wizard.component.scss'],
})
export class AppCreateWizardComponent implements AfterViewInit {
  @ViewChild('wizardPanel') wizardPanelTemplate!: TemplateRef<void>;
  @ViewChild('previewPanel') previewPanelTemplate!: TemplateRef<void>;

  @ViewChild('gettingStartedStep') gettingStartedStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('basicInfoStep') basicInfoStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('publishingStep') publishingStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('integrationPointsStep') integrationPointsStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('permissionsStep') permissionsStep!: TemplateRef<{ $implicit: Step }>;
  @ViewChild('reviewStep') reviewStep!: TemplateRef<{ $implicit: Step }>;

  private readonly fb = inject(FormBuilder);
  private readonly router = inject(Router);
  private readonly route = inject(ActivatedRoute);
  private readonly appStoreService = inject(AppStoreService);
  private readonly appVersionService = inject(AppVersionService);
  private readonly modalFormService = inject(ModalFormService);
  private readonly destroyRef = inject(DestroyRef);
  private readonly userSessionService = inject(UserSessionService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly location = inject(Location);
  private readonly layoutService = inject(LayoutService);

  readonly isMobile = this.layoutService.isMobile;
  readonly panels = signal<PanelConfig[]>([]);
  readonly steps = signal<Step[]>([]);
  readonly currentStep = signal<number>(1);
  readonly visible = signal<boolean>(true);

  readonly isLastStep = computed(
    () => this.steps().length > 0 && this.currentStep() === this.steps().at(-1)?.value,
  );

  readonly prevStepValue = computed(() => {
    const idx = this.steps().findIndex((s) => s.value === this.currentStep());
    return idx > 0 ? this.steps()[idx - 1].value : null;
  });

  isSubmitting = signal<boolean>(false);
  submissionError = signal<string | null>(null);
  submittedApp = signal<AppDefinition | null>(null);
  isEditMode = signal<boolean>(false);
  existingAppId: string | null = null;
  existingAppData = signal<AppDefinition | null>(null);
  draftVersion = signal<AppVersion | null>(null);
  baselineVersion = signal<AppVersion | null>(null);
  appForm: FormGroup;
  formValue: Signal<AppFormValue | undefined>;
  submitAction: 'draft' | 'review' | null = null;
  pendingBumpType = signal<VersionBumpType | null>(null);
  pendingChangelog = signal<string | null>(null);

  readonly availableScreens = AVAILABLE_SCREENS;
  readonly Object = Object;

  readonly previewData = computed<AppPreviewData>(() => {
    const fv = this.formValue();
    const session = this.userSessionService.currentUserSession();
    return {
      name: fv?.basicInfo.name ?? '',
      shortDescription: fv?.basicInfo.shortDescription ?? '',
      description: fv?.basicInfo.description ?? '',
      iconUrl: fv?.basicInfo.iconUrl,
      developerName: session?.name ?? 'You',
      visibility: fv?.publishing.visibility ?? 'global',
      feeModel: this.toFeeModel(fv?.publishing.feeType, fv?.publishing.feeAmount),
      integrationPoints: fv?.integration.points ?? [],
      hasHealthCheck: isDefined(fv?.basicInfo.healthCheckUrl) && fv.basicInfo.healthCheckUrl !== '',
    };
  });

  changedFields = computed(() => {
    if (!this.isEditMode()) return null;
    const orig = this.existingAppData();
    const fv = this.formValue();
    const baselineVersion = this.baselineVersion();
    const baseline =
      baselineVersion ??
      (isNullOrUndefined(orig?.version.activeVersionId) ? null : orig);
    if (!baseline) return null;
    return {
      name: fv?.basicInfo.name !== baseline.name,
      shortDescription:
        fv?.basicInfo.shortDescription !== baseline.shortDescription,
      description: fv?.basicInfo.description !== baseline.description,
      iconUrl: fv?.basicInfo.iconUrl !== baseline.iconUrl,
      healthCheckUrl:
        fv?.basicInfo.healthCheckUrl !== (baseline.healthCheckUrl ?? ''),
      integrationPoints: !isEqual(
        fv?.integration.points,
        baseline.integrationPoints,
      ),
      visibility: fv?.publishing.visibility !== baseline.visibility,
      feeModel: !isEqual(
        this.toFeeModel(fv?.publishing.feeType, fv?.publishing.feeAmount),
        baseline.feeModel,
      ),
    };
  });

  constructor() {
    this.appForm = this.fb.group({
      basicInfo: this.fb.group({
        name: ['', Validators.required],
        shortDescription: [
          '',
          [Validators.required, Validators.maxLength(100)],
        ],
        description: ['', Validators.required],
        iconUrl: [''],
        healthCheckUrl: ['', [Validators.pattern('https?://.+')]],
      }),
      publishing: this.fb.group({
        visibility: ['global'],
        feeType: ['free'],
        feeAmount: [null as number | null],
      }),
      integration: this.fb.group({
        points: this.fb.array([], Validators.required),
      }),
    });

    this.appForm.get('publishing.feeType')?.valueChanges.subscribe((feeType) => {
      const feeAmountCtrl = this.appForm.get('publishing.feeAmount');
      if (feeType === 'free') {
        feeAmountCtrl?.clearValidators();
        feeAmountCtrl?.setValue(null);
      } else {
        feeAmountCtrl?.setValidators([Validators.required, Validators.min(0.01)]);
      }
      feeAmountCtrl?.updateValueAndValidity();
    });

    this.formValue = toSignal(
      this.appForm.valueChanges.pipe(
        startWith(null),
        map(() => this.appForm.value as AppFormValue),
      ),
    );

    this.bootstrapEditContext();
  }

  get integrationPoints() {
    return this.appForm.get('integration.points') as FormArray;
  }

  toggleIntegrationPoint(screenId: string, event: CheckboxChangeEvent) {
    const isChecked = event.checked as boolean;
    const existingIndex = this.integrationPoints.controls.findIndex(
      (x) => x.value.screenId === screenId,
    );

    if (isChecked) {
      if (existingIndex === -1) {
        this.integrationPoints.push(
          this.fb.group({
            screenId: [screenId],
            baseUrl: [
              '',
              [Validators.required],
            ],
            requiredPermissions: [[]],
          }),
        );
      }
    } else if (existingIndex >= 0) {
      this.integrationPoints.removeAt(existingIndex);
    }
  }

  isScreenSelected(screenId: string): boolean {
    return this.integrationPoints.controls.some(
      (x) => x.value.screenId === screenId,
    );
  }

  getIntegrationPointControl(screenId: string): FormGroup | undefined {
    return this.integrationPoints.controls.find(
      (x) => x.value.screenId === screenId,
    ) as FormGroup | undefined;
  }

  getOriginalIntegrationPoint(screenId: string): IntegrationPoint | undefined {
    return this.existingAppData()?.integrationPoints.find(
      (p) => p.screenId === screenId,
    );
  }

  ngAfterViewInit(): void {
    const isCreate = !this.isEditMode();
    const allSteps: Step[] = [
      ...(isCreate ? [{ value: 1, header: 'Getting Started', content: this.gettingStartedStep, disableNext: false }] : []),
      { value: isCreate ? 2 : 1, header: 'Basic Info',         content: this.basicInfoStep,         disableNext: true },
      { value: isCreate ? 3 : 2, header: 'Publishing',         content: this.publishingStep,         disableNext: true },
      { value: isCreate ? 4 : 3, header: 'Integration Points', content: this.integrationPointsStep, disableNext: true },
      { value: isCreate ? 5 : 4, header: 'Permissions',        content: this.permissionsStep,        disableNext: false },
      { value: isCreate ? 6 : 5, header: 'Review',             content: this.reviewStep,             disableNext: false, hideDefaultFooter: true },
    ];
    this.steps.set(allSteps);
    this.updateStepStates();

    this.appForm.valueChanges
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(() => this.updateStepStates());

    this.panels.set([
      { content: this.wizardPanelTemplate, scrollable: true },
      { content: this.previewPanelTemplate, scrollable: true },
    ]);
  }

  updateStepStates(): void {
    this.steps.update((steps) =>
      steps.map((step) => {
        if (step.header === 'Basic Info') {
          return { ...step, disableNext: this.appForm.get('basicInfo')?.invalid ?? true };
        }
        if (step.header === 'Publishing') {
          return { ...step, disableNext: this.appForm.get('publishing')?.invalid ?? true };
        }
        if (step.header === 'Integration Points') {
          return { ...step, disableNext: this.appForm.get('integration')?.invalid ?? true };
        }
        return step;
      }),
    );
  }

  onWizardComplete(): void {
    this.submit();
  }

  onWizardCancel(): void {
    this.location.back();
  }

  saveDraft(): void {
    this.submitAction = 'draft';
    this.submit();
  }

  openSubmitVersionDialog(): void {
    const isFirstSubmission =
      this.existingAppData()?.version.activeVersionId == null;
    const dummyField = createTextAreaField('dummy', 'dummy', undefined);

    const modalFields = [
      ...(isFirstSubmission
        ? []
        : [
            createDropdownField(
              'bumpType',
              'Version Bump',
              [
                { label: 'Patch — bug fixes, no new features', value: 'patch' },
                {
                  label: 'Minor — new features, backward compatible',
                  value: 'minor',
                },
                { label: 'Major — breaking changes', value: 'major' },
              ],
              undefined,
              {
                validations: [
                  { name: 'required', validator: Validators.required },
                ],
              },
            ),
          ]),
      createTextAreaField('changelog', 'Changelog', undefined, {
        placeholder: 'Describe what changed in this version...',
        validations: [{ name: 'required', validator: Validators.required }],
      }),
    ];

    this.modalFormService
      .openListItemModal<{ bumpType: string; changelog: string }>({
        modalConfig: {
          modalComponent: ModalListFormComponent,
          modalTitle: 'Submit New Version',
          modalFields,
          onSubmit: (data, ref) =>
            new Promise((resolve) => {
              this.pendingBumpType.set(
                isFirstSubmission
                  ? 'patch'
                  : (data['bumpType'] as VersionBumpType),
              );
              this.pendingChangelog.set(data['changelog']);
              ref.close();
              this.submitAction = 'review';
              this.submit();
              resolve(true);
            }),
        },
        itemData: { bumpType: '', changelog: '' },
        destroyRef: this.destroyRef,
        field: dummyField,
      })
      .subscribe();
  }

  submit(): void {
    if (!this.appForm.valid || this.isSubmitting()) {
      return;
    }

    this.submissionError.set(null);
    this.isSubmitting.set(true);

    const formValue = this.appForm.value as AppFormValue;
    const action = this.submitAction || 'draft';

    if (isDefined(this.existingAppId) && this.existingAppData()) {
      this.handleEditSubmit(formValue, action);
    } else {
      this.handleCreateSubmit(formValue, action);
    }
  }

  private handleEditSubmit(
    formValue: AppFormValue,
    action: 'draft' | 'review',
  ): void {
    if (!isDefined(this.existingAppId)) return;

    if (action === 'draft') {
      const draft = this.draftVersion();
      if (!isDefined(draft)) {
        this.submissionError.set('No draft version found to update.');
        this.isSubmitting.set(false);
        return;
      }
      this.appVersionService
        .updateVersion(this.existingAppId, draft.id, {
          name: formValue.basicInfo.name,
          description: formValue.basicInfo.description,
          shortDescription: formValue.basicInfo.shortDescription,
          iconUrl: formValue.basicInfo.iconUrl,
          healthCheckUrl: formValue.basicInfo.healthCheckUrl,
          integrationPoints: formValue.integration.points.map((p) => ({
            screenId: p.screenId,
            requiredPermissions: p.requiredPermissions,
            baseUrl: p.baseUrl,
          })),
        })
        .pipe(
          tap((updated) => {
            this.draftVersion.set(updated);
            this.visible.set(false);
            this.router.navigate(['/app-store/my-created-apps']).catch(() => {});
          }),
          catchError(() => {
            this.submissionError.set(
              'Could not update your draft. Please try again.',
            );
            return of(null);
          }),
          finalize(() => {
            this.isSubmitting.set(false);
            this.submitAction = null;
          }),
        )
        .subscribe();
      return;
    }

    const bumpType = this.pendingBumpType();
    const changelog = this.pendingChangelog();
    if (!isDefined(bumpType) || !isDefined(changelog)) {
      this.isSubmitting.set(false);
      return;
    }

    const changed = this.changedFields();
    const payload: SubmitAppVersionRequest = { bumpType, changelog };
    if (isDefined(changed)) {
      if (changed.name) payload.name = formValue.basicInfo.name;
      if (changed.description)
        payload.description = formValue.basicInfo.description;
      if (changed.shortDescription)
        payload.shortDescription = formValue.basicInfo.shortDescription;
      if (changed.iconUrl) payload.iconUrl = formValue.basicInfo.iconUrl;
      if (changed.healthCheckUrl)
        payload.healthCheckUrl = formValue.basicInfo.healthCheckUrl;
      if (changed.integrationPoints)
        payload.integrationPoints = formValue.integration.points.map((p) => ({
          screenId: p.screenId,
          requiredPermissions: p.requiredPermissions,
          baseUrl: p.baseUrl,
        }));
      if (changed.visibility) payload.visibility = formValue.publishing.visibility;
      if (changed.feeModel)
        payload.feeModel = this.toFeeModel(
          formValue.publishing.feeType,
          formValue.publishing.feeAmount,
        );
    }
    this.appVersionService
      .submitVersion(this.existingAppId, payload)
      .pipe(
        tap(() => {
          const existingApp = this.existingAppData();
          if (isDefined(existingApp)) {
            this.submittedApp.set(existingApp);
            this.visible.set(false);
          }
        }),
        catchError(() => {
          this.submissionError.set(
            'Could not submit your app version. Please try again.',
          );
          return of(null);
        }),
        finalize(() => {
          this.isSubmitting.set(false);
          this.submitAction = null;
          this.pendingBumpType.set(null);
          this.pendingChangelog.set(null);
        }),
      )
      .subscribe();
  }

  private handleCreateSubmit(
    formValue: AppFormValue,
    action: 'draft' | 'review',
  ): void {
    const user = this.userSessionService.currentUserSession();
    const payload: Partial<AppDefinition> = {
      ...formValue.basicInfo,
      iconUrl: formValue.basicInfo.iconUrl ?? 'assets/default-app-icon.png',
      developerId: user?.id ?? 'unknown-user',
      developerName: user?.name ?? 'Unknown Developer',
      integrationPoints: formValue.integration.points,
      categories: ['Productivity'],
      tags: [],
      visibility: formValue.publishing.visibility,
      feeModel: this.toFeeModel(formValue.publishing.feeType, formValue.publishing.feeAmount),
    };

    this.appStoreService
      .createApp(payload)
      .pipe(
        switchMap((createdApp) => {
          const bumpType = this.pendingBumpType();
          const changelog = this.pendingChangelog();
          if (
            action === 'review' &&
            isDefined(bumpType) &&
            isDefined(changelog)
          ) {
            return this.appVersionService
              .submitVersion(createdApp.id, { bumpType, changelog })
              .pipe(
                map(() => createdApp),
                catchError(() => of(createdApp)),
              );
          }
          return of(createdApp);
        }),
        tap((app) => {
          if (isDefined(app)) {
            this.submittedApp.set(app);
            this.visible.set(false);
          }
        }),
        catchError(() => {
          this.submissionError.set(
            'Could not save your app. Please try again.',
          );
          return of(null);
        }),
        finalize(() => {
          this.isSubmitting.set(false);
          this.submitAction = null;
          this.pendingBumpType.set(null);
          this.pendingChangelog.set(null);
        }),
      )
      .subscribe();
  }

  toFeeModel(feeType: string | undefined, feeAmount: number | null | undefined): FeeModel | null {
    if (
      isNullOrUndefined(feeType) ||
      feeType === 'free' ||
      isNullOrUndefined(feeAmount) ||
      feeAmount <= 0
    ) {
      return null;
    }
    return { type: feeType as FeeType, amount: feeAmount };
  }

  getFeePreviewLabel(feeType: string, feeAmount: number | null): string {
    if (isNullOrUndefined(feeAmount) || feeAmount <= 0 || feeType === 'free') return '';
    const formatted = formatCurrency(feeAmount, 'en-ZA', 'R', 'ZAR');
    if (feeType === 'perActiveDevice') {
      const example = formatCurrency(feeAmount * 200, 'en-ZA', 'R', 'ZAR');
      return `e.g. an org with 200 active devices would pay ${example}`;
    }
    return `${formatted} per installation`;
  }

  formatScreenId(screenId: string): string {
    return screenId.replace(/([A-Z])/g, ' $1').replace(/^./, (s) => s.toUpperCase()).trim();
  }

  goToAppDetail(appId: string): void {
    this.router.navigate(['/app-store', appId]).catch(() => {});
  }

  goToMarketplace(): void {
    this.location.back();
  }

  private bootstrapEditContext(): void {
    const navState = history.state as { appToEdit?: AppDefinition } | undefined;
    const appFromState = navState?.appToEdit;
    const appIdFromQuery = this.route.snapshot.queryParamMap.get('appId');

    if (appFromState) {
      this.enterEditMode(appFromState);
      return;
    }

    if (isDefined(appIdFromQuery)) {
      this.loadAppForEdit(appIdFromQuery);
    }
  }

  private loadAppForEdit(appId: string): void {
    this.appStoreService
      .getAppById(appId, this.clientDataService.getSelectedClient()?.id ?? '')
      .pipe(
        tap((app) => {
          if (app) {
            this.enterEditMode(app);
          }
        }),
        catchError(() => {
          this.submissionError.set('Could not load the app to edit.');
          return of(null);
        }),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe();
  }

  private enterEditMode(app: AppDefinition): void {
    this.existingAppId = app.id;
    this.existingAppData.set({ ...app });
    this.isEditMode.set(true);

    this.appVersionService
      .getVersions(app.id)
      .pipe(
        tap((versions) => {
          const draft = versions.find((v) => v.status === 'draft') ?? null;
          this.draftVersion.set(draft);
          const isPreFirstApproval = isNullOrUndefined(
            app.version.activeVersionId,
          );
          const latestVersion = versions.at(0) ?? null;
          const versionSource =
            draft ?? (isPreFirstApproval ? latestVersion : null);
          this.baselineVersion.set(versionSource);
          const source = versionSource ?? (!isPreFirstApproval ? app : null);
          if (!source) return;
          const srcFeeModel = source.feeModel;
          this.appForm.patchValue({
            basicInfo: {
              name: source.name,
              shortDescription: source.shortDescription,
              description: source.description,
              iconUrl: source.iconUrl,
              healthCheckUrl: source.healthCheckUrl ?? '',
            },
            publishing: {
              visibility: source.visibility ?? 'global',
              feeType: srcFeeModel?.type ?? 'free',
              feeAmount: srcFeeModel?.amount ?? null,
            },
          });
          this.integrationPoints.clear();
          source.integrationPoints.forEach((point) => {
            this.integrationPoints.push(
              this.fb.group({
                screenId: [point.screenId],
                baseUrl: [
                  point.baseUrl,
                  [Validators.required],
                ],
                requiredPermissions: [point.requiredPermissions],
              }),
            );
          });
          this.updateStepStates();
        }),
        catchError(() => {
          if (isNullOrUndefined(app.version.activeVersionId)) {
            return of([]);
          }
          const appFeeModel = app.feeModel;
          this.appForm.patchValue({
            basicInfo: {
              name: app.name,
              shortDescription: app.shortDescription,
              description: app.description,
              iconUrl: app.iconUrl,
              healthCheckUrl: app.healthCheckUrl ?? '',
            },
            publishing: {
              visibility: app.visibility ?? 'global',
              feeType: appFeeModel?.type ?? 'free',
              feeAmount: appFeeModel?.amount ?? null,
            },
          });
          this.integrationPoints.clear();
          app.integrationPoints.forEach((point) => {
            this.integrationPoints.push(
              this.fb.group({
                screenId: [point.screenId],
                baseUrl: [
                  point.baseUrl,
                  [Validators.required],
                ],
                requiredPermissions: [point.requiredPermissions],
              }),
            );
          });
          this.updateStepStates();
          return of([]);
        }),
        takeUntilDestroyed(this.destroyRef),
      )
      .subscribe();
  }
}
